// ── Injection function ──────────────────────────────────────────────────────

function injectSecondGradeFields(filePath, newFields) {
  const src = fs.readFileSync(filePath, 'utf8');
  // Find the unique pattern: end of second-grade section + third-grade start
  const marker = /\n    \},\n    'third-grade':/;
  const match = src.match(marker);
  if (!match) {
    throw new Error(`Could not find second-grade/third-grade boundary in ${filePath}`);
  }
  // Insert the new fields before the closing }, of the second-grade section
  const insertPos = match.index;
  const updated = src.slice(0, insertPos) + '\n' + newFields + '\n    },\n    \'third-grade\':' + src.slice(match.index + match[0].length);
  fs.writeFileSync(filePath, updated, 'utf8');
  console.log(`  Updated ${path.basename(path.dirname(filePath))}/${path.basename(filePath)}`);
}

